INSERT INTO lessons (id, category_id, slug, title, summary, difficulty_level, estimated_minutes, sort_order, is_published)
VALUES ('40000000-0000-0000-0000-000000000012', 'c3000000-0000-0000-0000-000000000007', 'sequential-circuits',
  '順序回路', 'ラッチ、フリップフロップ、レジスタ、カウンタ、有限状態機械（FSM）。', 3, 35, 1, true);

INSERT INTO lesson_blocks (lesson_id, block_type, content, sort_order) VALUES
('40000000-0000-0000-0000-000000000012', 'markdown', '{"text": "# 順序回路\n\n**順序回路**は、出力が**現在の入力と過去の状態（記憶）**の両方で決まる回路です。記憶要素（フリップフロップ）を含み、クロック信号に同期して状態が変化します。\n\nレジスタ、カウンタ、制御ユニット、メモリなど、CPU のほぼ全ての構成要素が順序回路です。\n\n## ラッチとフリップフロップ\n\n### SR ラッチ（Set-Reset Latch）\n\n最も基本的な記憶素子。2つの NOR ゲート（または NAND ゲート）のフィードバック接続で構成。\n\n| S | R | Q (次状態) | 動作 |\n|---|---|---|---|\n| 0 | 0 | Q (保持) | 状態維持 |\n| 0 | 1 | 0 | リセット |\n| 1 | 0 | 1 | セット |\n| 1 | 1 | 不定 | **禁止**（両方同時は未定義） |\n\n### D ラッチ（Data Latch）\n\nSR ラッチの S=D, R=D̄ として禁止状態を除去。Enable 信号で制御。\n\n- Enable=1: Q = D（透過、入力がそのまま出力）\n- Enable=0: Q = 保持（最後の値を記憶）\n\n問題: Enable=1 の間は入力の変化が出力に透過する（**透過性**）→ タイミング制御が困難。"}', 0),

('40000000-0000-0000-0000-000000000012', 'markdown', '{"text": "### D フリップフロップ（Edge-triggered）\n\nクロック信号の**エッジ（立ち上がりまたは立ち下がり）**でのみ入力をサンプルする記憶素子。\n\n- 立ち上がりエッジ時: Q ← D\n- それ以外: Q = 保持\n\nラッチの透過性問題を解決。同期回路設計の基本素子です。\n\n内部実装: 2つの D ラッチを直列接続（マスター・スレーブ構成）。\n\n### タイミングパラメータ\n\n| パラメータ | 意味 |\n|---|---|\n| **セットアップ時間 (tₛ)** | クロックエッジ前に D が安定している必要がある最小時間 |\n| **ホールド時間 (tₕ)** | クロックエッジ後に D が安定している必要がある最小時間 |\n| **伝搬遅延 (tₚ)** | クロックエッジから Q が変化するまでの時間 |\n\n### クロック周波数の上限\n\n$$T_{clk} \\geq t_p + t_{comb} + t_s$$\n\ntₚ = フリップフロップの伝搬遅延、t_comb = 組合せ回路の遅延、tₛ = セットアップ時間\n\nこの制約が**クロック周波数の上限**を決定します。パイプラインで組合せ回路を分割すると t_comb が小さくなり、周波数を上げられます。"}', 1),

('40000000-0000-0000-0000-000000000012', 'markdown', '{"text": "## レジスタとレジスタファイル\n\n### レジスタ\n\nn個の D フリップフロップを並列に並べたもの。nビットのデータを1クロックで格納。\n\n### レジスタファイル\n\nCPU 内の複数レジスタの集合。RISC-V の場合、32個の 64ビットレジスタ（x0〜x31）。\n\n構成:\n- **読み出しポート** × 2: レジスタ番号（5ビット）を入力し、データを出力。組合せ回路（MUX）で実装。読み出しは即座。\n- **書き込みポート** × 1: レジスタ番号、書き込みデータ、書き込み有効信号。クロックエッジで書き込み。\n\nレジスタファイルの読み出しが ID ステージ、書き込みが WB ステージで行われるため、パイプラインのデータハザードが発生します。"}', 2),

('40000000-0000-0000-0000-000000000012', 'markdown', '{"text": "## 有限状態機械（FSM: Finite State Machine）\n\nFSM は順序回路を抽象的に記述するモデルで、以下で定義されます:\n\n- 状態の有限集合 S\n- 入力アルファベット Σ\n- 遷移関数 δ: S × Σ → S\n- 出力関数\n- 初期状態 s₀\n\n### ムーア機械 vs ミーリ機械\n\n| | ムーア | ミーリ |\n|---|---|---|\n| 出力依存 | 状態のみ | 状態 + 現在の入力 |\n| 出力変化 | クロックエッジ後 | 入力変化時（非同期的） |\n| 状態数 | 多い | 少ない（入力で出力を区別） |\n| 安定性 | 高い（グリッチなし） | 入力のグリッチが出力に伝搬する可能性 |\n\n### CPU の制御ユニット\n\nCPU の制御ユニットは FSM として設計されます。現在の状態（命令の実行フェーズ）と入力（命令のオペコード）に基づいて、制御信号（ALU演算選択、メモリ読み書き、レジスタ書き込み等）を生成。\n\n**学習のポイント**: ラッチの透過性問題とフリップフロップによる解決。セットアップ/ホールド時間がクロック周波数の上限を決定すること。レジスタファイルの読み書きポートの構成。FSM が CPU 制御の設計手法であること。"}', 3);

