INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000011', 'd3000000-0000-0000-0000-000000000005',
  'multiple_choice', 'ド・モルガンの法則 (A·B)'' はどれに等しい？',
  '[{"id":"a","text":"A'' · B''"},{"id":"b","text":"A'' + B''"},{"id":"c","text":"A · B''"},{"id":"d","text":"A + B"}]',
  '{"answer":"b"}',
  'ド・モルガンの法則: (A·B)'' = A'' + B''。「ANDの否定は、否定のOR」です。',
  1, 10),
('f2000000-0000-0000-0000-000000000012', 'd3000000-0000-0000-0000-000000000005',
  'multiple_choice', '任意の論理関数を単一種類のゲートで実装できるのは？',
  '[{"id":"a","text":"AND"},{"id":"b","text":"OR"},{"id":"c","text":"XOR"},{"id":"d","text":"NAND"}]',
  '{"answer":"d"}',
  'NAND ゲートは機能的完全（functionally complete）です。NOT、AND、OR をすべて NAND だけで構成できます。NOR も同様に機能的完全です。',
  2, 10),
('f2000000-0000-0000-0000-000000000013', 'd3000000-0000-0000-0000-000000000005',
  'fill_in_blank', 'XOR ゲートの出力は、2つの入力が___とき1になる。',
  NULL, '{"answers":["異なる","異なるとき","異なった"]}',
  'XOR（排他的論理和）は2つの入力が異なるとき1、等しいとき0を出力します。A⊕B = A''·B + A·B''',
  3, 10);

-- Quiz: Combinational Circuits
INSERT INTO quizzes (id, category_id, title, difficulty_level, is_published)
VALUES ('d3000000-0000-0000-0000-000000000006', 'c3000000-0000-0000-0000-000000000006',
  '組合せ回路クイズ', 2, true);

INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000014', 'd3000000-0000-0000-0000-000000000006',
  'multiple_choice', 'リプルキャリー加算器の nビット加算における遅延の計算量は？',
  '[{"id":"a","text":"O(1)"},{"id":"b","text":"O(log n)"},{"id":"c","text":"O(n)"},{"id":"d","text":"O(n²)"}]',
  '{"answer":"c"}',
  'リプルキャリー加算器ではキャリーが各段を順番に伝搬するため、遅延は O(n) です。先読みキャリー加算器（CLA）で O(log n) に改善できます。',
  1, 10),
('f2000000-0000-0000-0000-000000000015', 'd3000000-0000-0000-0000-000000000006',
  'multiple_choice', 'ALU で A - B を計算する方法は？',
  '[{"id":"a","text":"A AND (NOT B)"},{"id":"b","text":"A + (NOT B) + 1"},{"id":"c","text":"A XOR B"},{"id":"d","text":"(NOT A) + B"}]',
  '{"answer":"b"}',
  '2の補数表現では、-B = NOT B + 1 です。よって A - B = A + (NOT B) + 1。加算回路を再利用して減算を実装できます。',
  2, 10);

-- Quiz: Sequential Circuits
INSERT INTO quizzes (id, category_id, title, difficulty_level, is_published)
VALUES ('d3000000-0000-0000-0000-000000000007', 'c3000000-0000-0000-0000-000000000007',
