INSERT INTO questions (id, quiz_id, question_type, prompt, options, correct_answer, explanation, sort_order, points) VALUES
('f2000000-0000-0000-0000-000000000016', 'd3000000-0000-0000-0000-000000000007',
  'multiple_choice', 'D フリップフロップがラッチと異なる最大の特徴は？',
  '[{"id":"a","text":"入力が2つある"},{"id":"b","text":"クロックのエッジでのみ入力をサンプルする"},{"id":"c","text":"非同期でリセットできる"},{"id":"d","text":"出力が反転する"}]',
  '{"answer":"b"}',
  'D フリップフロップはクロックのエッジ（立ち上がりまたは立ち下がり）でのみ入力をサンプルし、それ以外では値を保持します。ラッチはイネーブル中に入力が透過します。',
  1, 10),
('f2000000-0000-0000-0000-000000000017', 'd3000000-0000-0000-0000-000000000007',
  'multiple_choice', 'クロック周波数の上限を決定する要因の組み合わせは？',
  '[{"id":"a","text":"トランジスタ数と消費電力"},{"id":"b","text":"フリップフロップの伝搬遅延 + 組合せ回路の遅延 + セットアップ時間"},{"id":"c","text":"レジスタ数とメモリ帯域幅"},{"id":"d","text":"パイプライン段数とキャッシュサイズ"}]',
  '{"answer":"b"}',
  'T_clk ≥ t_p + t_comb + t_s。フリップフロップの伝搬遅延、組合せ回路（クリティカルパス）の遅延、セットアップ時間の合計がクロック周期の下限を決めます。',
  2, 10),
('f2000000-0000-0000-0000-000000000018', 'd3000000-0000-0000-0000-000000000007',
  'true_false', 'ムーア型FSMの出力は、現在の状態のみに依存し、入力には直接依存しない。',
  '[{"id":"true","text":"正しい"},{"id":"false","text":"誤り"}]',
  '{"answer":true}',
  'ムーア型FSMの出力は現在の状態のみで決まります。ミーリ型FSMは状態と現在の入力の両方に依存します。',
  3, 10);
